import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { ArenaLeaderboardParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/ArenaLeaderboardParser';

export class ArenaLeaderboardEvent extends MessageEvent implements IMessageEvent
{
constructor(callback: Function)
{
super(callback, ArenaLeaderboardParser);
}

public getParser(): ArenaLeaderboardParser
{
return this.parser as ArenaLeaderboardParser;
}
}
